import type { Lang } from './digiclara';

type Video = {
  title: string;
  url: string;
  embed: string;
};

export type ArticleBodyBase = {
  quick: string[];
  sections: [string, string[]][];
  steps: string[];
  tips: string[];
  warnings: string[];
  faq: [string, string][];
  conclusion: string;
  video?: Video;
};

type Copy = {
  quick: string[];
  contextTitle: string;
  context: string[];
  decisionTitle: string;
  decision: string[];
  practiceTitle: string;
  practice: string[];
  steps: string[];
  tips: string[];
  warnings: string[];
  faq: [string, string][];
  conclusion: string;
  video?: Video;
};

const body = (copy: Copy): ArticleBodyBase => ({
  quick: copy.quick,
  sections: [
    [copy.contextTitle, copy.context],
    [copy.decisionTitle, copy.decision],
    [copy.practiceTitle, copy.practice],
  ],
  steps: copy.steps,
  tips: copy.tips,
  warnings: copy.warnings,
  faq: copy.faq,
  conclusion: copy.conclusion,
  ...(copy.video ? { video: copy.video } : {}),
});

